INSERT INTO `booking_condition_setup` (`id`, `year`, `booking_condition`, `status`) VALUES
(1, '2025', 'আলু কোল্ড ষ্টোরেজে দেওয়ার পূর্বে অবশ্যই তারিখ লইতে হবে।', 'ACTIVE'),
(2, '2025', 'ছালকাটা,পোকালাগা,কাটা,অপুষ্ট আলু রাখা চলিবে না।(যেহেতু কর্ত্পক্ষের পক্ষে সম্পূর্ণ আলু চেক করা সম্ভব নহে। তাই এ ব্যাপারে সম্পূর্ণ দায়িত্ব গ্রাহকের)।', 'ACTIVE'),
(3, '2025', 'নির্ধারিত তারিখে আলু না রাখিলে জমা টাকা ফেরৎ পাওয়া যাবে না এবং আলু সংক্ষণের সম্পূর্ণ ভাড়া দিতে হইবে।', 'ACTIVE'),
(4, '2025', 'এই বুকিং এ আলু কম ঢুকিলে উল্লেখিত বস্তার ভাড়া পরিশোধ করিতে হইবে।', 'ACTIVE'),
(5, '2025', 'এই বুকিং এ আলু বেশি ঢুকিলে যদি কোন প্রকার সমস্যার সৃষ্টি হয় তাহলে তার নিজ খরচে চেম্বার হতে আলুর বস্তা বাহির করে দেওয়া হবে।', 'ACTIVE'),
(6, '2025', 'বুকিং রশিদ নিয়ে এসে আলু ঢুকানো প্রবেশ পত্র নিতে হবে। তারপর আলু ঢুকিবে।', 'ACTIVE'),
(7, '2026', 'আলু কোল্ড ষ্টোরেজে দেওয়ার পূর্বে অবশ্যই তারিখ লইতে হবে।', 'ACTIVE'),
(8, '2026', 'ছালকাটা,পোকালাগা,কাটা,অপুষ্ট আলু রাখা চলিবে না।(যেহেতু কর্ত্পক্ষের পক্ষে সম্পূর্ণ আলু চেক করা সম্ভব নহে। তাই এ ব্যাপারে সম্পূর্ণ দায়িত্ব গ্রাহকের)।', 'ACTIVE'),
(9, '2026', 'নির্ধারিত তারিখে আলু না রাখিলে জমা টাকা ফেরৎ পাওয়া যাবে না ।', 'ACTIVE'),
(10, '2025', 'এই বুকিং এ আলু কম ঢুকিলে উল্লেখিত বস্তার ভাড়া পরিশোধ করিতে হইবে।', 'INACTIVE'),
(11, '2026', 'এই বুকিং এ আলু বেশি ঢুকিলে যদি কোন প্রকার সমস্যার সৃষ্টি হয় তাহলে তার নিজ খরচে চেম্বার হতে আলুর বস্তা বাহির করে দেওয়া হবে।', 'ACTIVE'),
(12, '2026', 'বুকিং রশিদ নিয়ে এসে আলু ঢুকানো প্রবেশ পত্র নিতে হবে। তারপর আলু ঢুকিবে।', 'ACTIVE'),
(13, '2026', 'পরবর্তীতে আলু ডেলিভারী সময় লেবার চার্জ প্রযোয্য হবে অথবা প্রতি কেজি .50 পয়সা হারে আদায় করা হবে।', 'ACTIVE'),
(14, '2025', 'প্রতি বস্তায় ৬৫ কেজির বেশী আলু নেওয়া হইবে না। কম হইলেও একই ভাড়া লাগিবে। ৬৫ কেজির বেশী আলু রাখিলে অতিরিক্ত ভাড়া চার্জ করা  হইবে।', 'ACTIVE'),
(15, '2026', 'প্রতি বস্তায় 50 কেজির বেশী আলু নেওয়া হইবে না। কম হইলেও একই ভাড়া লাগিবে। ', 'ACTIVE');
